import type { QueryEngineLogLevel } from '@prisma/client-common'
import { enginesVersion } from '@prisma/engines-version'
import type { TracingHelper } from '@prisma/instrumentation-contract'

export type AccelerateHeaders = {
  'Content-Type': string
  'Prisma-Engine-Hash': string
  'Prisma-Engine-Version': string
  'X-Capture-Telemetry'?: string
  'X-Transaction-Id'?: string
  Accept: string
  Authorization: string
  traceparent?: string
}

type HeaderBuilderOptions = {
  traceparent?: string
  transactionId?: string
}

export class HeaderBuilder {
  readonly apiKey: string
  readonly tracingHelper: TracingHelper
  readonly logLevel: QueryEngineLogLevel
  readonly logQueries: boolean | undefined
  readonly engineHash: string

  constructor({
    apiKey,
    tracingHelper,
    logLevel,
    logQueries,
    engineHash,
  }: {
    apiKey: string
    tracingHelper: TracingHelper
    logLevel: QueryEngineLogLevel
    logQueries: boolean | undefined
    engineHash: string
  }) {
    this.apiKey = apiKey
    this.tracingHelper = tracingHelper
    this.logLevel = logLevel
    this.logQueries = logQueries
    this.engineHash = engineHash
  }

  build({ traceparent, transactionId }: HeaderBuilderOptions = {}): AccelerateHeaders {
    const headers: AccelerateHeaders = {
      Accept: 'application/json',
      Authorization: `Bearer ${this.apiKey}`,
      'Content-Type': 'application/json',
      'Prisma-Engine-Hash': this.engineHash,
      'Prisma-Engine-Version': enginesVersion,
    }

    if (this.tracingHelper.isEnabled()) {
      headers.traceparent = traceparent ?? this.tracingHelper.getTraceParent()
    }

    if (transactionId) {
      headers['X-Transaction-Id'] = transactionId
    }

    const captureTelemetry = this.#buildCaptureSettings()

    if (captureTelemetry.length > 0) {
      headers['X-Capture-Telemetry'] = captureTelemetry.join(', ')
    }

    return headers
  }

  #buildCaptureSettings(): string[] {
    const captureTelemetry: string[] = []

    if (this.tracingHelper.isEnabled()) {
      captureTelemetry.push('tracing')
    }

    if (this.logLevel) {
      captureTelemetry.push(this.logLevel)
    }

    if (this.logQueries) {
      captureTelemetry.push('query')
    }

    return captureTelemetry
  }
}

import type {
  WebpackConfiguration as Configuration,
  ModuleConfig,
  ResolveConfig,
  RulesConfig,
} from './types.ts';

function mergePluginsField(
  defaultPlugins: Required<Configuration>['plugins'] = [],
  customPlugins: Required<Configuration>['plugins'] = []
): Required<Configuration>['plugins'] {
  return [...defaultPlugins, ...customPlugins];
}

function mergeRulesField(
  defaultRules: RulesConfig[] = [],
  customRules: RulesConfig[] = []
): ModuleConfig['rules'] {
  return [...defaultRules, ...customRules];
}

function mergeExtensionsField(
  { extensions: defaultExtensions = [] }: ResolveConfig,
  { extensions: customExtensions = [] }: ResolveConfig
): ResolveConfig['extensions'] {
  return [...defaultExtensions, ...customExtensions];
}

function mergeAliasField(
  { alias: defaultAlias = {} }: ResolveConfig,
  { alias: customAlias = {} }: ResolveConfig
): ResolveConfig['alias'] {
  return {
    ...defaultAlias,
    ...customAlias,
  };
}

function mergeModuleField(a: ModuleConfig, b: ModuleConfig): ModuleConfig {
  return {
    ...a,
    ...b,
    rules: mergeRulesField(a.rules || [], b.rules || []),
  };
}

function mergeResolveField(
  { resolve: defaultResolve = {} }: Configuration,
  { resolve: customResolve = {} }: Configuration
): ResolveConfig {
  return {
    ...defaultResolve,
    ...customResolve,
    alias: mergeAliasField(defaultResolve, customResolve),
    extensions: mergeExtensionsField(defaultResolve, customResolve),
  };
}

function mergeOptimizationField(
  { optimization: defaultOptimization = {} }: Configuration,
  { optimization: customOptimization = {} }: Configuration
): Configuration['optimization'] {
  return {
    ...defaultOptimization,
    ...customOptimization,
  };
}

export function mergeConfigs(config: Configuration, customConfig: Configuration): Configuration {
  return {
    // We'll always load our configurations after the custom config.
    // So, we'll always load the stuff we need.
    ...customConfig,
    ...config,
    devtool: customConfig.devtool || config.devtool,
    plugins: mergePluginsField(config.plugins, customConfig.plugins),
    module: mergeModuleField(config.module || {}, customConfig.module || {}),
    resolve: mergeResolveField(config, customConfig),
    optimization: mergeOptimizationField(config, customConfig),
  };
}

