import { type Context, type Span, SpanKind, type SpanOptions } from '@opentelemetry/api'
import type { SqlQuery } from '@prisma/driver-adapter-utils'

import { QueryEvent } from './events'
import type { SchemaProvider } from './schema'
import { assertNever, DeepReadonly } from './utils'

export type SpanCallback<R> = (span?: Span, context?: Context) => R

export type ExtendedSpanOptions = SpanOptions & {
  name: string
}

// A smaller version of the equivalent interface from `@prisma/internals`
export interface TracingHelper {
  isEnabled(): boolean
  runInChildSpan<R>(nameOrOptions: string | ExtendedSpanOptions, callback: SpanCallback<R>): R
}

export const noopTracingHelper: TracingHelper = {
  isEnabled() {
    return false
  },
  runInChildSpan(_, callback) {
    return callback()
  },
}

export function providerToOtelSystem(provider: SchemaProvider): string {
  switch (provider) {
    case 'postgresql':
    case 'postgres':
    case 'prisma+postgres':
      return 'postgresql'
    case 'sqlserver':
      return 'mssql'
    case 'mysql':
    case 'sqlite':
    case 'cockroachdb':
    case 'mongodb':
      return provider
    default:
      assertNever(provider, `Unknown provider: ${provider}`)
  }
}

export async function withQuerySpanAndEvent<T>({
  query,
  tracingHelper,
  provider,
  onQuery,
  execute,
}: {
  query: DeepReadonly<SqlQuery>
  tracingHelper: TracingHelper
  provider: SchemaProvider
  onQuery?: (event: QueryEvent) => void
  execute: () => Promise<T>
}): Promise<T> {
  const callback =
    onQuery === undefined
      ? execute
      : async () => {
          const timestamp = new Date()
          const startInstant = performance.now()
          const result = await execute()
          const endInstant = performance.now()

          onQuery({
            timestamp,
            duration: endInstant - startInstant,
            query: query.sql,
            params: query.args,
          })

          return result
        }

  if (!tracingHelper.isEnabled()) {
    return callback()
  }

  return await tracingHelper.runInChildSpan(
    {
      name: 'db_query',
      kind: SpanKind.CLIENT,
      attributes: {
        'db.query.text': query.sql,
        'db.system.name': providerToOtelSystem(provider),
      },
    },
    callback,
  )
}

import { BasicBuilder } from './BasicBuilder'
import { Writer } from './Writer'

export type ExportFrom = NamespaceExport | BindingsExport | ExportAllFrom

export class NamespaceExport implements BasicBuilder {
  constructor(
    private from: string,
    private namespace: string,
  ) {}

  write(writer: Writer<undefined>): void {
    writer.write(`export * as ${this.namespace} from '${this.from}'`)
  }
}

export class BindingsExport implements BasicBuilder {
  private namedExports: NamedExport[] = []
  constructor(private from: string) {}

  named(namedExport: string | NamedExport) {
    if (typeof namedExport === 'string') {
      namedExport = new NamedExport(namedExport)
    }
    this.namedExports.push(namedExport)
    return this
  }

  write(writer: Writer<undefined>): void {
    writer
      .write('export ')
      .write('{ ')
      .writeJoined(', ', this.namedExports)
      .write(' }')

      .write(` from "${this.from}"`)
  }
}

export class NamedExport implements BasicBuilder {
  private alias: string | undefined
  private type = false

  constructor(readonly name: string) {}

  as(alias: string) {
    this.alias = alias
    return this
  }

  typeOnly(): this {
    this.type = true
    return this
  }

  write(writer: Writer): void {
    if (this.type) {
      writer.write('type ')
    }
    writer.write(this.name)
    if (this.alias) {
      writer.write(' as ').write(this.alias)
    }
  }
}

export class ExportAllFrom implements BasicBuilder {
  constructor(private from: string) {}

  asNamespace(namespace: string) {
    return new NamespaceExport(this.from, namespace)
  }

  named(binding: string | NamedExport) {
    return new BindingsExport(this.from).named(binding)
  }

  write(writer: Writer): void {
    writer.write(`export * from "${this.from}"`)
  }
}

export function moduleExportFrom(from: string) {
  return new ExportAllFrom(from)
}

export function namedExport(name: string) {
  return new NamedExport(name)
}

import { handleError } from '../../cli/logging';
import type {
	MaybeArray,
	MergedRollupOptions,
	RollupOptions,
	RollupWatcher
} from '../rollup/types';
import { ensureArray } from '../utils/ensureArray';
import { error, logInvalidOption } from '../utils/logs';
import { mergeOptions } from '../utils/options/mergeOptions';
import { URL_WATCH } from '../utils/urls';
import { loadFsEvents } from './fsevents-importer';
import { WatchEmitter } from './WatchEmitter';

export default function watch(configs: RollupOptions[] | RollupOptions): RollupWatcher {
	const emitter = new WatchEmitter() as RollupWatcher;

	watchInternal(configs, emitter).catch(error => {
		handleError(error);
	});

	return emitter;
}

function ensureTrailingSlash(path: string): string {
	if (path[path.length - 1] !== '/') {
		return `${path}/`;
	}
	return path;
}

function checkWatchConfig(config: MergedRollupOptions[]): void {
	for (const item of config) {
		if (typeof item.watch !== 'boolean' && item.watch?.allowInputInsideOutputPath) {
			break;
		}
		if (item.input && item.output) {
			const input = typeof item.input === 'string' ? ensureArray(item.input) : item.input;
			const outputs = ensureArray(item.output);
			for (const index in input) {
				const inputPath = input[index as keyof typeof input];
				if (typeof inputPath !== 'string') {
					continue;
				}
				const outputWithInputAsSubPath = outputs.find(
					({ dir }) => dir && ensureTrailingSlash(inputPath).startsWith(ensureTrailingSlash(dir))
				);
				if (outputWithInputAsSubPath) {
					error(
						logInvalidOption(
							'watch',
							URL_WATCH,
							`the input "${inputPath}" is a subpath of the output "${outputWithInputAsSubPath.dir}"`
						)
					);
				}
			}
		}
	}
}

async function watchInternal(configs: MaybeArray<RollupOptions>, emitter: RollupWatcher) {
	const optionsList = await Promise.all(
		ensureArray(configs).map(config => mergeOptions(config, true))
	);
	const watchOptionsList = optionsList.filter(config => config.watch !== false);
	if (watchOptionsList.length === 0) {
		return error(
			logInvalidOption(
				'watch',
				URL_WATCH,
				'there must be at least one config where "watch" is not set to "false"'
			)
		);
	}
	checkWatchConfig(watchOptionsList);
	await loadFsEvents();
	const { Watcher } = await import('./watch');
	new Watcher(watchOptionsList, emitter);
}

import React from 'react';

import { darken, transparentize } from 'polished';
import { styled } from 'storybook/theming';

const BadgeWrapper = styled.div<BadgeProps>(
  ({ theme, compact }) => ({
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: theme.typography.size.s1,
    fontWeight: theme.typography.weight.bold,
    lineHeight: '12px',
    minWidth: 20,
    borderRadius: 20,
    padding: compact ? '4px 7px' : '4px 10px',
  }),
  {
    svg: {
      height: 12,
      width: 12,
      marginRight: 4,
      marginTop: -2,

      path: {
        fill: 'currentColor',
      },
    },
  },
  ({ theme, status }) => {
    switch (status) {
      case 'critical': {
        return {
          color: theme.fgColor.critical,
          background: theme.bgColor.critical,
          boxShadow: `inset 0 0 0 1px ${theme.borderColor.critical}`,
        };
      }
      case 'negative': {
        return {
          color: theme.fgColor.negative,
          background: theme.bgColor.negative,
          boxShadow: `inset 0 0 0 1px ${theme.borderColor.negative}`,
        };
      }
      case 'warning': {
        return {
          color: theme.fgColor.warning,
          background: theme.bgColor.warning,
          boxShadow: `inset 0 0 0 1px ${theme.borderColor.warning}`,
        };
      }
      case 'neutral': {
        return {
          color: theme.fgColor.muted,
          background: theme.base === 'dark' ? theme.barBg : theme.background.app,
          boxShadow: `inset 0 0 0 1px ${transparentize(0.8, theme.textMutedColor)}`,
        };
      }
      case 'positive': {
        return {
          color: theme.fgColor.positive,
          background: theme.bgColor.positive,
          boxShadow: `inset 0 0 0 1px ${theme.borderColor.positive}`,
        };
      }
      case 'active': {
        return {
          color:
            theme.base === 'light' ? darken(0.1, theme.color.secondary) : theme.color.secondary,
          background: theme.background.hoverable,
          boxShadow: `inset 0 0 0 1px ${transparentize(0.9, theme.color.secondary)}`,
        };
      }
      default: {
        return {};
      }
    }
  }
);

export interface BadgeProps {
  compact?: boolean;
  status?: 'positive' | 'negative' | 'neutral' | 'warning' | 'critical' | 'active';
  children?: React.ReactNode;
}

export const Badge = ({ ...props }: BadgeProps) => {
  return <BadgeWrapper {...props} />;
};

import { Subscribable } from './subscribable'

type Listener = (focused: boolean) => void

type SetupFn = (
  setFocused: (focused?: boolean) => void,
) => (() => void) | undefined

export class FocusManager extends Subscribable<Listener> {
  #focused?: boolean
  #cleanup?: () => void

  #setup: SetupFn

  constructor() {
    super()
    this.#setup = (onFocus) => {
      // addEventListener does not exist in React Native, but window does
      // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
      if (typeof window !== 'undefined' && window.addEventListener) {
        const listener = () => onFocus()
        // Listen to visibilitychange
        window.addEventListener('visibilitychange', listener, false)

        return () => {
          // Be sure to unsubscribe if a new handler is set
          window.removeEventListener('visibilitychange', listener)
        }
      }
      return
    }
  }

  protected onSubscribe(): void {
    if (!this.#cleanup) {
      this.setEventListener(this.#setup)
    }
  }

  protected onUnsubscribe() {
    if (!this.hasListeners()) {
      this.#cleanup?.()
      this.#cleanup = undefined
    }
  }

  setEventListener(setup: SetupFn): void {
    this.#setup = setup
    this.#cleanup?.()
    this.#cleanup = setup((focused) => {
      if (typeof focused === 'boolean') {
        this.setFocused(focused)
      } else {
        this.onFocus()
      }
    })
  }

  setFocused(focused?: boolean): void {
    const changed = this.#focused !== focused
    if (changed) {
      this.#focused = focused
      this.onFocus()
    }
  }

  onFocus(): void {
    const isFocused = this.isFocused()
    this.listeners.forEach((listener) => {
      listener(isFocused)
    })
  }

  isFocused(): boolean {
    if (typeof this.#focused === 'boolean') {
      return this.#focused
    }

    // document global can be unavailable in react native
    // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
    return globalThis.document?.visibilityState !== 'hidden'
  }
}

export const focusManager = new FocusManager()

import path from "node:path";
import fs from "fs-extra";
import picocolors from "picocolors";
import { isFolderEmpty } from "./is-folder-empty";

export function validateDirectory(directory: string): {
  valid: boolean;
  root: string;
  projectName: string;
  error?: string;
} {
  // Basic sanity checks on the provided directory string to prevent
  // unsafe paths from flowing into tooling that invokes git or other CLIs.
  if (
    !directory ||
    typeof directory !== "string" ||
    directory.trim() === "" ||
    directory.includes("\0")
  ) {
    const safeDirectory = typeof directory === "string" ? directory : "";
    return {
      valid: false,
      root: "",
      projectName: "",
      error: `${picocolors.dim(
        safeDirectory || "<empty>"
      )} is not a valid directory name - please try a different location`
    };
  }

  const root = path.resolve(directory);
  const projectName = path.basename(root);

  // Prevent resolved paths that could be misinterpreted as command-line options
  // when passed to tools like git, and ensure the project name is well-formed.
  const unsafeRoot = !root || root.startsWith("-") || root.includes("\0");
  const invalidProjectName =
    !projectName || !/^[a-zA-Z0-9._-]+$/.test(projectName);

  if (unsafeRoot || invalidProjectName) {
    return {
      valid: false,
      root,
      projectName,
      error: `${picocolors.dim(
        projectName || root || "<unknown>"
      )} is not a valid directory - please try a different location`
    };
  }

  const exists = fs.existsSync(root);

  const stat = fs.lstatSync(root, { throwIfNoEntry: false });
  if (stat && !stat.isDirectory()) {
    return {
      valid: false,
      root,
      projectName,
      error: `${picocolors.dim(
        projectName
      )} is not a directory - please try a different location`
    };
  }

  if (exists) {
    const { isEmpty, conflicts } = isFolderEmpty(root);
    if (!isEmpty) {
      return {
        valid: false,
        root,
        projectName,
        error: `${picocolors.dim(projectName)} (${root}) has ${
          conflicts.length
        } conflicting ${
          conflicts.length === 1 ? "file" : "files"
        } - please try a different location`
      };
    }
  }

  return { valid: true, root, projectName };
}

