import { DevEnvironment } from '../environment'
import type { ServerModuleRunnerOptions } from '../../ssr/runtime/serverModuleRunner'
import { createServerModuleRunner } from '../../ssr/runtime/serverModuleRunner'
import { createServerHotChannel } from '../hmr'
import type { Environment } from '../../environment'

export function createRunnableDevEnvironment(
  name: string,
  config: ResolvedConfig,
  context: RunnableDevEnvironmentContext = {},
): RunnableDevEnvironment {
  if (context.transport == null) {
    context.transport = createServerHotChannel()
  }
  if (context.hot == null) {
    context.hot = true
  }

  return new RunnableDevEnvironment(name, config, context)
}

export interface RunnableDevEnvironmentContext extends Omit<
  DevEnvironmentContext,
  'hot'
> {
  runner?: (
    environment: RunnableDevEnvironment,
    options?: ServerModuleRunnerOptions,
  ) => ModuleRunner
  runnerOptions?: ServerModuleRunnerOptions
  hot?: boolean
}

export function isRunnableDevEnvironment(
  environment: Environment,
): environment is RunnableDevEnvironment {
  return environment instanceof RunnableDevEnvironment
}

class RunnableDevEnvironment extends DevEnvironment {
  private _runner: ModuleRunner | undefined
  private _runnerFactory:
    | ((
        environment: RunnableDevEnvironment,
        options?: ServerModuleRunnerOptions,
      ) => ModuleRunner)
    | undefined
  private _runnerOptions: ServerModuleRunnerOptions | undefined

  constructor(
    name: string,
    config: ResolvedConfig,
    context: RunnableDevEnvironmentContext,
  ) {
    super(name, config, context as DevEnvironmentContext)
    this._runnerFactory = context.runner
    this._runnerOptions = context.runnerOptions
  }

  get runner(): ModuleRunner {
    if (this._runner) {
      return this._runner
    }
    const factory = this._runnerFactory || createServerModuleRunner
    this._runner = factory(this, this._runnerOptions)
    return this._runner
  }

  override async close(): Promise<void> {
    await super.close()
    if (this._runner) {
      await this._runner.close()
    }
  }
}

export type { RunnableDevEnvironment }

import type {
  AriaNode,
  AriaTemplateNode,
} from 'ivya/aria'
import type {
  DomainMatchResult,
  DomainSnapshotAdapter,
  MatchersObject,
} from 'vitest'
import * as aria from 'ivya/aria'
import { Snapshots } from 'vitest'
import { getBrowserState } from '../utils'

getBrowserState().aria = aria

const {
  generateAriaTree,
  matchAriaTree,
  parseAriaTemplate,
  renderAriaTemplate,
  renderAriaTree,
} = aria

const ariaSnapshotAdapter: DomainSnapshotAdapter<AriaNode, AriaTemplateNode> = {
  name: 'aria',

  capture(received) {
    if (received instanceof Element) {
      return generateAriaTree(received)
    }
    throw new TypeError('aria adapter expects an Element')
  },

  render(captured) {
    return wrapNewlines(renderAriaTree(captured))
  },

  parseExpected(input) {
    // increase limit so that yaml parse error can reach `toMatchAriaSnapshot` callsite in user test files
    const limit = Error.stackTraceLimit
    Error.stackTraceLimit = limit + 20
    try {
      return parseAriaTemplate(input.trim())
    }
    finally {
      Error.stackTraceLimit = limit
    }
  },

  match(captured, expected): DomainMatchResult {
    const r = matchAriaTree(captured, expected)
    if (r.pass) {
      return { pass: true }
    }
    return {
      pass: false,
      message: 'Accessibility tree does not match expected template',
      resolved: wrapNewlines(r.resolved),
      expected: wrapNewlines(renderAriaTemplate(expected)),
    }
  },
}

// ensure newlines for diff/snapshot readability
function wrapNewlines(s: string) {
  return `\n${s}\n`
}

export const ariaMatchers: MatchersObject = {
  toMatchAriaSnapshot(actual: unknown) {
    return Snapshots.toMatchDomainSnapshot.call(this, ariaSnapshotAdapter, actual)
  },
  toMatchAriaInlineSnapshot(actual: Element, inlineSnapshot?: string) {
    return Snapshots.toMatchDomainInlineSnapshot.call(this, ariaSnapshotAdapter, actual, inlineSnapshot)
  },
}

// internal flag to allow expect.poll for snapshot matchers
for (const matcher of Object.values(ariaMatchers)) {
  Object.assign(matcher, {
    __vitest_poll_takeover__: true,
  })
}

import type { EnvironmentModuleNode } from 'vite'
import type { Vitest } from '../node/core'
import type { ModuleGraphData } from '../types/general'
import { getTestFileEnvironment } from './environments'

export async function getModuleGraph(
  ctx: Vitest,
  projectName: string,
  testFilePath: string,
): Promise<ModuleGraphData> {
  const graph: Record<string, string[]> = {}
  const externalized = new Set<string>()
  const inlined = new Set<string>()

  const project = ctx.getProjectByName(projectName)
  const browser = project.config.browser.enabled

  const environment = project.config.experimental.viteModuleRunner === false
    ? project.vite.environments.__vitest__
    : getTestFileEnvironment(project, testFilePath, browser)

  if (!environment) {
    throw new Error(`Cannot find environment for ${testFilePath}`)
  }
  const seen = new Map<EnvironmentModuleNode, string>()

  function get(mod?: EnvironmentModuleNode) {
    if (!mod || !mod.id) {
      return
    }
    if (
      mod.id === '\0vitest/browser'
      // the export helper is injected in all vue files
      // so the module graph becomes too bouncy
      || mod.id.includes('plugin-vue:export-helper')
    ) {
      return
    }
    if (seen.has(mod)) {
      return seen.get(mod)
    }
    const id = clearId(mod.id)
    seen.set(mod, id)
    if (id.startsWith('__vite-browser-external:')) {
      const external = id.slice('__vite-browser-external:'.length)
      externalized.add(external)
      return external
    }
    const external = project._resolver.wasExternalized(id)
    if (typeof external === 'string') {
      externalized.add(external)
      return external
    }
    if (browser && mod.file?.includes(project.browser!.vite.config.cacheDir)) {
      externalized.add(mod.id)
      return id
    }
    inlined.add(id)
    const mods = Array.from(mod.importedModules).filter(
      i => i.id && !i.id.includes('/vitest/dist/'),
    )
    graph[id] = mods.map(m => get(m)).filter(
      Boolean,
    ) as string[]
    return id
  }

  get(environment.moduleGraph.getModuleById(testFilePath))
  project.config.setupFiles.forEach((setupFile) => {
    get(environment.moduleGraph.getModuleById(setupFile))
  })

  return {
    graph,
    externalized: Array.from(externalized),
    inlined: Array.from(inlined),
  }
}

function clearId(id?: string | null) {
  return id?.replace(/\?v=\w+$/, '') || ''
}

import {FakeFS, WatchFileOptions, WatchFileCallback} from '../FakeFS';
import {Path}                                        from '../path';

import {CustomStatWatcher}                           from './watchFile/CustomStatWatcher';

const statWatchersByFakeFS = new WeakMap<FakeFS<Path>, Map<Path, CustomStatWatcher<Path>>>();

export function watchFile<P extends Path>(
  fakeFs: FakeFS<P>,
  path: P,
  a: WatchFileOptions | WatchFileCallback,
  b?: WatchFileCallback,
) {
  let bigint: boolean;
  let persistent: boolean;
  let interval: number;

  let listener: WatchFileCallback;

  switch (typeof a) {
    case `function`: {
      bigint = false;
      persistent = true;
      interval = 5007;

      listener = a;
    } break;

    default: {
      ({
        bigint = false,
        persistent = true,
        interval = 5007,
      } = a);

      listener = b!;
    } break;
  }

  let statWatchers = statWatchersByFakeFS.get(fakeFs);
  if (typeof statWatchers === `undefined`)
    statWatchersByFakeFS.set(fakeFs, statWatchers = new Map());

  let statWatcher = statWatchers.get(path);
  if (typeof statWatcher === `undefined`) {
    statWatcher = CustomStatWatcher.create<P>(fakeFs, path, {bigint});

    statWatchers.set(path, statWatcher);
  }

  statWatcher.registerChangeListener(listener, {persistent, interval});

  return statWatcher as CustomStatWatcher<P>;
}

export function unwatchFile<P extends Path>(fakeFs: FakeFS<P>, path: P, cb?: WatchFileCallback) {
  const statWatchers = statWatchersByFakeFS.get(fakeFs);
  if (typeof statWatchers === `undefined`)
    return;

  const statWatcher = statWatchers.get(path);
  if (typeof statWatcher === `undefined`)
    return;

  if (typeof cb === `undefined`)
    statWatcher.unregisterAllChangeListeners();
  else
    statWatcher.unregisterChangeListener(cb);

  if (!statWatcher.hasChangeListeners()) {
    statWatcher.stop();
    statWatchers.delete(path);
  }
}

export function unwatchAllFiles(fakeFs: FakeFS<Path>) {
  const statWatchers = statWatchersByFakeFS.get(fakeFs);
  if (typeof statWatchers === `undefined`)
    return;

  for (const path of statWatchers.keys()) {
    unwatchFile(fakeFs, path);
  }
}

import type { Node } from "acorn";
import { parse } from "acorn";
import { simple } from "acorn-walk";
import type { SourceType } from "../constants/ast";
import { ECMA_VERSION } from "../constants/ast";
import { getExpressionStringAtPos, isPositionWithinNode } from "./utils";

export class PeekOverlayExpressionIdentifier {
  private parsedScript?: Node;
  private options: PeekOverlayExpressionIdentifierOptions;

  constructor(
    options: PeekOverlayExpressionIdentifierOptions,
    script?: string,
  ) {
    this.options = options;

    if (script) this.updateScript(script);
  }

  hasParsedScript() {
    return !!this.parsedScript;
  }

  updateScript(script: string) {
    try {
      this.parsedScript = parse(script, {
        ecmaVersion: ECMA_VERSION,
        sourceType: this.options.sourceType,
      });
    } catch (e) {
      // eslint-disable-next-line no-console
      console.error(e);
    }
  }

  clearScript() {
    this.parsedScript = undefined;
  }

  async extractExpressionAtPosition(pos: number): Promise<string> {
    return new Promise((resolve, reject) => {
      if (!this.parsedScript) {
        throw "PeekOverlayExpressionIdentifier - No valid script found";
      }

      let nodeFound: Node | undefined;

      simple(this.parsedScript, {
        MemberExpression(node: Node) {
          if (!nodeFound && isPositionWithinNode(node, pos)) {
            nodeFound = node;
          }
        },
        ExpressionStatement(node: Node) {
          if (!nodeFound && isPositionWithinNode(node, pos)) {
            nodeFound = node;
          }
        },
      });

      if (nodeFound) {
        const expressionFound = getExpressionStringAtPos(
          nodeFound,
          pos,
          this.options,
        );

        if (expressionFound) {
          resolve(expressionFound);
        } else {
          reject(
            "PeekOverlayExpressionIdentifier - No expression found at position",
          );
        }
      }

      reject("PeekOverlayExpressionIdentifier - No node found");
    });
  }
}

export interface PeekOverlayExpressionIdentifierOptions {
  sourceType: SourceType;
  thisExpressionReplacement?: string;
}

import React, { useMemo } from "react";
import { ListItem } from "../../../List";
import type { EntityItemProps } from "./EntityItem.types";
import clx from "classnames";
import { EditableEntityName } from "../../EditableEntityName";
import { useActiveDoubleClick } from "../../../__hooks__";

export const EntityItem = (props: EntityItemProps) => {
  const { onDoubleClick, startIcon, ...rest } = props;

  const doubleClickOverride = useActiveDoubleClick(
    props.isSelected || false,
    onDoubleClick,
  );

  const {
    canEdit,
    isEditing,
    isLoading,
    normalizeName = true,
    onEditComplete,
    onNameSave,
    validateName,
  } = props.nameEditorConfig;

  const inEditMode = canEdit ? isEditing : false;

  // Use List Item custom title prop to show the editable name
  const customTitle = useMemo(() => {
    return (
      <EditableEntityName
        canEdit={canEdit}
        hasError={props.hasError}
        icon={startIcon}
        isEditing={isEditing}
        isFixedWidth
        isLoading={isLoading}
        name={props.title}
        normalizeName={normalizeName}
        onExitEditing={onEditComplete}
        onNameSave={onNameSave}
        showEllipsis
        size="medium"
        validateName={validateName}
      />
    );
  }, [
    canEdit,
    isEditing,
    isLoading,
    normalizeName,
    onEditComplete,
    onNameSave,
    props.hasError,
    props.title,
    startIcon,
    validateName,
  ]);

  // Do not show right control if the visibility is hover and the item is in edit mode
  const rightControl = useMemo(() => {
    if (props.rightControlVisibility === "hover" && inEditMode) {
      return null;
    }

    return props.rightControl;
  }, [inEditMode, props.rightControl, props.rightControlVisibility]);

  return (
    <ListItem
      {...rest}
      className={clx("t--entity-item", props.className)}
      customTitleComponent={customTitle}
      dataTestId={`t--entity-item-${props.title}`}
      id={"entity-" + props.id}
      onDoubleClick={doubleClickOverride}
      rightControl={rightControl}
    />
  );
};

import type { UseFloatingOptions } from "@floating-ui/react/src/types";
import { useState, useMemo } from "react";
import {
  autoUpdate,
  flip,
  offset,
  useClick,
  useDismiss,
  useFloating,
  useInteractions,
  useRole,
} from "@floating-ui/react";

import type { PopoverProps } from "./types";

const DEFAULT_POPOVER_OFFSET = 10;

export function usePopover({
  defaultOpen = false,
  dismissClickOutside = false,
  duration = 0,
  initialFocus,
  isOpen: controlledOpen,
  modal = false,
  offset: offsetProp = DEFAULT_POPOVER_OFFSET,
  onClose,
  placement = "bottom",
  setOpen: setControlledOpen,
  triggerRef,
}: PopoverProps = {}) {
  const [uncontrolledOpen, setUncontrolledOpen] = useState(defaultOpen);
  const [labelId, setLabelId] = useState<string | undefined>();
  const [descriptionId, setDescriptionId] = useState<string | undefined>();
  const open = controlledOpen ?? uncontrolledOpen;
  const setOpen = setControlledOpen ?? setUncontrolledOpen;

  const config: Partial<UseFloatingOptions> = {
    placement,
    strategy: "fixed",
    whileElementsMounted: autoUpdate,
    middleware: [
      offset(offsetProp),
      flip({
        crossAxis: placement.includes("-"),
        fallbackAxisSideDirection: "end",
      }),
    ],
  };

  const data = useFloating({
    open,
    onOpenChange: setOpen,
    ...(modal ? {} : config),
  });

  const context = data.context;
  const click = useClick(context, {
    enabled: controlledOpen == null,
  });
  const dismiss = useDismiss(context, {
    escapeKey: !dismissClickOutside,
    outsidePress: (event) => {
      if (dismissClickOutside) return false;

      // By default, click to close popup only work inside the provider
      return Boolean(
        (event?.target as HTMLElement).closest("[data-theme-provider]"),
      );
    },
  });
  const role = useRole(context);
  const interactions = useInteractions([click, dismiss, role]);

  return useMemo(
    () => ({
      open,
      setOpen,
      ...interactions,
      ...data,
      modal,
      labelId,
      descriptionId,
      setLabelId,
      setDescriptionId,
      duration,
      triggerRef,
      initialFocus,
      onClose,
    }),
    [
      open,
      setOpen,
      interactions,
      data,
      modal,
      labelId,
      descriptionId,
      triggerRef,
      initialFocus,
      onClose,
    ],
  );
}

import { useCallback, type RefObject, useMemo } from "react";
import {
  useLayoutEffect,
  useResizeObserver,
  useValueEffect,
} from "@react-aria/utils";
import type { POSITION } from "@appsmith/wds";
import type { Orientation } from "@react-types/shared";

export interface GroupAria {
  orientation?: Orientation;
}

export function useGroupOrientation(
  props: {
    orientation?: Orientation;
    optionsLabelPosition?: keyof typeof POSITION;
  },
  ref: RefObject<HTMLDivElement>,
): GroupAria {
  const [{ orientation }, setOrientation] = useValueEffect({
    orientation: props.orientation ?? "vertical",
  });

  const updateOverflow = useCallback(() => {
    const computeOrientation = () => {
      if (props.orientation === "vertical") return "vertical";

      if (ref.current) {
        const options = Array.from(ref.current.children) as HTMLLIElement[];

        const containerSize = ref.current.getBoundingClientRect().width;
        const gap = toNumber(window.getComputedStyle(ref.current).gap);
        let calculatedSize = 0;

        for (const [i, item] of options.entries()) {
          const itemWidth = item.getBoundingClientRect().width;

          calculatedSize += itemWidth;

          if (i !== 0) {
            calculatedSize += gap;
          }

          if (calculatedSize >= containerSize) {
            return "vertical";
          }
        }
      }

      return "horizontal";
    };

    setOrientation(function* () {
      yield {
        orientation: "horizontal",
      };

      const orientation = computeOrientation();

      yield {
        orientation: orientation,
      };
    });
  }, [ref, setOrientation, props.orientation, props.optionsLabelPosition]);

  const parentRef = useMemo(
    () => ({
      get current() {
        return ref.current?.parentElement;
      },
    }),
    [ref],
  );

  useResizeObserver({
    ref: parentRef,
    onResize: updateOverflow,
  });
  useLayoutEffect(updateOverflow, [updateOverflow]);

  return {
    orientation,
  };
}

function toNumber(value: string) {
  const parsed = parseInt(value, 10);

  return isNaN(parsed) ? 0 : parsed;
}

import React from "react";
import type { ControlProps } from "./BaseControl";
import BaseControl from "./BaseControl";
import { Switch } from "@appsmith/ads";
import type { ControlType } from "constants/PropertyControlConstants";
import type { WrappedFieldProps } from "redux-form";
import { Field } from "redux-form";
import styled from "styled-components";

type SwitchFieldProps = WrappedFieldProps & {
  label: string;
  isRequired: boolean;
  info: string;
  disabled: boolean;
};

const SwitchWrapped = styled.div`
  flex-direction: row;
  display: flex;
  align-items: center;
  justify-content: end;
  position: relative;
  max-width: 60vw;
`;

// TODO: Fix this the next time the file is edited
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export class SwitchField extends React.Component<SwitchFieldProps, any> {
  get value() {
    const { input } = this.props;

    if (typeof input.value !== "string") return !!input.value;
    else {
      if (input.value.toLocaleLowerCase() === "false") return false;
      else return !!input.value;
    }
  }

  render() {
    return (
      <SwitchWrapped data-testid={this.props.input.name}>
        {/* TODO: refactor so that the label of the field props is also passed down and a part of Switch.*/}
        <Switch
          className="switch-control"
          isDisabled={this.props.disabled}
          isSelected={this.value}
          name={this.props.input.name}
          onChange={(isSelected) => this.props.input.onChange(isSelected)}
        />
      </SwitchWrapped>
    );
  }
}

class SwitchControl extends BaseControl<SwitchControlProps> {
  render() {
    const { configProperty, disabled, info, isRequired, label } = this.props;

    return (
      <Field
        component={SwitchField}
        disabled={disabled}
        info={info}
        isRequired={isRequired}
        label={label}
        name={configProperty}
      />
    );
  }

  getControlType(): ControlType {
    return "SWITCH";
  }
}

export interface SwitchControlProps extends ControlProps {
  info?: string;
}

export default SwitchControl;

import {
  AUTOCOMMIT_CONFIRM_DISABLE_MESSAGE,
  AUTOCOMMIT_DISABLE,
  createMessage,
} from "ee/constants/messages";
import {
  Button,
  Callout,
  Modal,
  ModalBody,
  ModalContent,
  ModalFooter,
  ModalHeader,
  Text,
} from "@appsmith/ads";
import React, { useCallback } from "react";
import AnalyticsUtil from "ee/utils/AnalyticsUtil";
import noop from "lodash/noop";
import styled from "styled-components";

const StyledModalContent = styled(ModalContent)`
  width: 640px;
`;

const StyledModalHeader = styled(ModalHeader)`
  margin: 0;
`;

interface DisableAutocommitModalViewProps {
  isAutocommitDisableModalOpen?: boolean;
  isToggleAutocommitLoading?: boolean;
  toggleAutocommit?: () => void;
  toggleAutocommitDisableModal?: (open: boolean) => void;
}

function DisableAutocommitModalView({
  isAutocommitDisableModalOpen = false,
  isToggleAutocommitLoading = false,
  toggleAutocommit = noop,
  toggleAutocommitDisableModal = noop,
}: DisableAutocommitModalViewProps) {
  const handleDisableAutocommit = useCallback(() => {
    toggleAutocommit();
    AnalyticsUtil.logEvent("GS_AUTO_COMMIT_DISABLED");
    toggleAutocommitDisableModal(false);
  }, [toggleAutocommit, toggleAutocommitDisableModal]);

  const handleModalOpenChange = useCallback(
    (open: boolean) => {
      if (!open) toggleAutocommitDisableModal(false);
    },
    [toggleAutocommitDisableModal],
  );

  return (
    <Modal
      onOpenChange={handleModalOpenChange}
      open={isAutocommitDisableModalOpen}
    >
      <StyledModalContent data-testid="t--autocommit-git-modal">
        <StyledModalHeader>
          {createMessage(AUTOCOMMIT_DISABLE)}
        </StyledModalHeader>
        <ModalBody>
          <Callout kind="warning">
            <Text>{createMessage(AUTOCOMMIT_CONFIRM_DISABLE_MESSAGE)}</Text>
          </Callout>
        </ModalBody>
        <ModalFooter>
          <Button
            className="t--autocommit-modal-cta-button"
            isLoading={isToggleAutocommitLoading}
            kind="primary"
            onClick={handleDisableAutocommit}
            size="md"
          >
            {createMessage(AUTOCOMMIT_DISABLE)}
          </Button>
        </ModalFooter>
      </StyledModalContent>
    </Modal>
  );
}

export default DisableAutocommitModalView;

import type BaseLayoutComponent from "layoutSystems/anvil/layoutComponents/BaseLayoutComponent";
import type { LayoutProps, WidgetLayoutProps } from "../anvilTypes";
import LayoutFactory from "layoutSystems/anvil/layoutComponents/LayoutFactory";

export interface WidgetLayoutPositionInfo {
  layoutOrder: string[];
  rowIndex: number;
  widgetLayoutProps: WidgetLayoutProps;
}

export function getWidgetLayoutMetaInfo(
  parentLayout: LayoutProps | null,
  widgetId: string,
  layoutOrder: string[] = [],
): WidgetLayoutPositionInfo | null {
  if (!parentLayout) return null;

  const Comp: typeof BaseLayoutComponent = LayoutFactory.get(
    parentLayout.layoutType,
  );

  if (Comp.rendersWidgets) {
    return findInWidgetLayout(parentLayout, widgetId, layoutOrder);
  }

  return findInLayout(parentLayout, widgetId, layoutOrder);
}

function findInWidgetLayout(
  parentLayout: LayoutProps,
  widgetId: string,
  order: string[] = [],
): WidgetLayoutPositionInfo | null {
  const widgetLayouts: WidgetLayoutProps[] =
    parentLayout.layout as WidgetLayoutProps[];
  const index: number = getWidgetIndex(parentLayout, widgetId);

  if (index === -1) return null;

  return {
    layoutOrder: [...order, parentLayout.layoutId],
    rowIndex: index,
    widgetLayoutProps: widgetLayouts[index],
  };
}

function findInLayout(
  parentLayout: LayoutProps,
  widgetId: string,
  order: string[] = [],
): WidgetLayoutPositionInfo | null {
  const layouts: LayoutProps[] = parentLayout.layout as LayoutProps[];
  let res: WidgetLayoutPositionInfo | null = null;

  for (let i = 0; i < layouts.length; i += 1) {
    const each: LayoutProps = layouts[i];
    let temp: WidgetLayoutPositionInfo | null = null;
    const Comp: typeof BaseLayoutComponent = LayoutFactory.get(each.layoutType);

    if (Comp.rendersWidgets) {
      temp = findInWidgetLayout(each, widgetId, [
        ...order,
        parentLayout.layoutId,
      ]);
    } else {
      temp = findInLayout(each, widgetId, [...order, parentLayout.layoutId]);
    }

    if (!!temp) {
      res = temp;
      break;
    }
  }

  return res;
}

function getWidgetIndex(props: LayoutProps, widgetId: string): number {
  const widgetLayouts: WidgetLayoutProps[] =
    props.layout as WidgetLayoutProps[];

  return widgetLayouts.findIndex(
    (item: WidgetLayoutProps) => item.widgetId === widgetId,
  );
}

import { getFormValues } from "redux-form";
import { API_EDITOR_FORM_NAME } from "ee/constants/forms";
import { getCurrentEnvironmentId } from "ee/selectors/environmentSelectors";
import get from "lodash/get";
import { useSelector } from "react-redux";
import {
  type Action,
  type ApiAction,
  isAPIAction,
  type Property,
} from "entities/Action";
import { getDatasources } from "ee/selectors/entitiesSelector";

function useGetFormActionValues() {
  const formValues = useSelector(getFormValues(API_EDITOR_FORM_NAME)) as Action;
  const datasources = useSelector(getDatasources);
  const currentEnvironment = useSelector(getCurrentEnvironmentId);

  // In an unlikely scenario where form is not initialised,
  // return empty values to avoid form ui issues
  if (!formValues || !isAPIAction(formValues)) {
    return {
      actionConfigurationBody: "",
      actionHeaders: [],
      actionParams: [],
      autoGeneratedHeaders: [],
      datasourceParams: [],
      datasourceHeaders: [],
    };
  }

  const actionConfigurationBody = get(
    formValues,
    "actionConfiguration.body",
    "",
  ) as string;

  const actionHeaders = get(
    formValues,
    "actionConfiguration.headers",
    [],
  ) as Property[];

  const autoGeneratedHeaders: ApiAction["actionConfiguration"]["autoGeneratedHeaders"] =
    get(formValues, "actionConfiguration.autoGeneratedHeaders", []);

  const actionParams = get(
    formValues,
    "actionConfiguration.queryParameters",
    [],
  ) as Property[];

  let datasourceFromAction: Action["datasource"] | undefined = get(
    formValues,
    "datasource",
  );

  if (datasourceFromAction && Object.hasOwn(datasourceFromAction, "id")) {
    datasourceFromAction = datasources.find(
      (d) => d.id === datasourceFromAction?.id,
    );
  }

  const datasourceHeaders = get(
    datasourceFromAction,
    `datasourceStorages.${currentEnvironment}.datasourceConfiguration.headers`,
    [],
  ) as Property[];

  const datasourceParams = get(
    datasourceFromAction,
    `datasourceStorages.${currentEnvironment}.datasourceConfiguration.queryParameters`,
    [],
  ) as Property[];

  return {
    actionConfigurationBody,
    actionHeaders,
    autoGeneratedHeaders,
    actionParams,
    datasourceHeaders,
    datasourceParams,
  };
}

