import { Logger, MedusaContainer, ModuleResolution } from "@medusajs/types"
import { promiseAll } from "@medusajs/utils"
import { asValue } from "@medusajs/deps/awilix"
import { EOL } from "os"
import { MODULE_SCOPE } from "../types"
import { loadInternalModule } from "./utils"

export const moduleLoader = async ({
  container,
  moduleResolutions,
  logger,
  migrationOnly,
  loaderOnly,
  schemaOnly,
}: {
  container: MedusaContainer
  moduleResolutions: Record<string, ModuleResolution>
  logger: Logger
  migrationOnly?: boolean
  loaderOnly?: boolean
  schemaOnly?: boolean
}): Promise<void> => {
  const resolutions = Object.values(moduleResolutions ?? {})
  const results = await promiseAll(
    resolutions.map((resolution) =>
      loadModule(
        container,
        resolution,
        logger!,
        migrationOnly,
        loaderOnly,
        schemaOnly
      )
    )
  )

  results.forEach((registrationResult, idx) => {
    if (registrationResult?.error) {
      const { error } = registrationResult
      logger?.error(
        `Could not resolve module: ${resolutions[idx].definition.label}. Error: ${error.message}${EOL}`
      )
      throw error
    }
  })
}

async function loadModule(
  container: MedusaContainer,
  resolution: ModuleResolution,
  logger: Logger,
  migrationOnly?: boolean,
  loaderOnly?: boolean,
  schemaOnly?: boolean
): Promise<{ error?: Error } | void> {
  const modDefinition = resolution.definition

  if (!modDefinition.key) {
    throw new Error(`Module definition is missing property "key"`)
  }

  const keyName = modDefinition.key
  const { scope } = resolution.moduleDeclaration ?? ({} as any)

  const canSkip =
    !resolution.resolutionPath &&
    !modDefinition.isRequired &&
    !modDefinition.defaultPackage

  if (scope === MODULE_SCOPE.EXTERNAL && !canSkip) {
    // TODO: implement external Resolvers
    // return loadExternalModule(...)
    throw new Error("External Modules are not supported yet.")
  }

  if (!scope) {
    let message = `The module ${resolution.definition.label} has to define its scope (internal | external)`

    container.register(keyName, asValue(undefined))

    return {
      error: new Error(message),
    }
  }

  if (resolution.resolutionPath === false) {
    container.register(keyName, asValue(undefined))

    return
  }

  return await loadInternalModule({
    container,
    resolution,
    logger,
    migrationOnly,
    loaderOnly,
    schemaOnly,
  })
}

import type { Tree } from '@nx/devkit';
import { joinPathFragments, names } from '@nx/devkit';
import { NormalizedNgRxFeatureStoreGeneratorOptions } from './normalize-options';
import { ensureTypescript } from '@nx/js/internal';

import { addGlobal } from '@nx/js';

let tsModule: typeof import('typescript');

export function addExportsToBarrel(
  tree: Tree,
  options: NormalizedNgRxFeatureStoreGeneratorOptions
): void {
  const indexFilePath = joinPathFragments(
    options.parentDirectory,
    '..',
    'index.ts'
  );
  if (!tree.exists(indexFilePath)) {
    return;
  }

  if (!tsModule) {
    tsModule = ensureTypescript();
  }
  const indexSourceText = tree.read(indexFilePath, 'utf-8');
  let sourceFile = tsModule.createSourceFile(
    indexFilePath,
    indexSourceText,
    tsModule.ScriptTarget.Latest,
    true
  );

  // Public API for the feature interfaces, selectors, and facade
  const { className, fileName } = names(options.name);
  const fileNameWithSubdir = options.subdirectory
    ? joinPathFragments(options.subdirectory, fileName)
    : fileName;
  const statePath = `./lib/${options.directory}/${fileNameWithSubdir}`;

  sourceFile = addGlobal(
    tree,
    sourceFile,
    indexFilePath,
    options.barrels
      ? `import * as ${className}Actions from '${statePath}.actions';`
      : `export * from '${statePath}.actions';`
  );
  sourceFile = addGlobal(
    tree,
    sourceFile,
    indexFilePath,
    options.barrels
      ? `import * as ${className}Feature from '${statePath}.reducer';`
      : `export * from '${statePath}.reducer';`
  );
  sourceFile = addGlobal(
    tree,
    sourceFile,
    indexFilePath,
    options.barrels
      ? `import * as ${className}Selectors from '${statePath}.selectors';`
      : `export * from '${statePath}.selectors';`
  );

  if (options.barrels) {
    sourceFile = addGlobal(
      tree,
      sourceFile,
      indexFilePath,
      `export { ${className}Actions, ${className}Feature, ${className}Selectors };`
    );
  }

  sourceFile = addGlobal(
    tree,
    sourceFile,
    indexFilePath,
    `export * from '${statePath}.models';`
  );

  if (options.facade) {
    sourceFile = addGlobal(
      tree,
      sourceFile,
      indexFilePath,
      `export * from '${statePath}.facade';`
    );
  }
}

import {
  addDependenciesToPackageJson,
  GeneratorCallback,
  Tree,
} from '@nx/devkit';
import { esbuildVersion } from '@nx/js/internal';
import {
  expressVersions,
  fastifyVersions,
  koaVersions,
  nodeTypesVersions,
  nxVersion,
  tslibVersion,
} from '../../../utils/versions';
import { NormalizedSchema } from './normalized-schema';

export function addProjectDependencies(
  tree: Tree,
  options: NormalizedSchema
): {
  installTask: GeneratorCallback;
  frameworkDependencies: Record<string, string>;
} {
  const bundlers = {
    webpack: {
      '@nx/webpack': nxVersion,
    },
    esbuild: {
      '@nx/esbuild': nxVersion,
      esbuild: esbuildVersion,
    },
  };

  const exprPkgVersions = expressVersions(tree);
  const koaPkgVersions = koaVersions(tree);
  const fastifyPkgVersions = fastifyVersions(tree);

  const frameworkDependencies = {
    express: {
      express: exprPkgVersions.expressVersion,
    },
    koa: {
      koa: koaPkgVersions.koaVersion,
    },
    fastify: {
      fastify: fastifyPkgVersions.fastifyVersion,
      'fastify-plugin': fastifyPkgVersions.fastifyPluginVersion,
      '@fastify/autoload': fastifyPkgVersions.fastifyAutoloadVersion,
      '@fastify/sensible': fastifyPkgVersions.fastifySensibleVersion,
    },
  };
  const frameworkDevDependencies = {
    express: {
      '@types/express': exprPkgVersions.expressTypingsVersion,
    },
    koa: {
      '@types/koa': koaPkgVersions.koaTypingsVersion,
    },
    fastify: {},
  };

  const typesNodeVersion = nodeTypesVersions(tree).typesNodeVersion;

  return {
    installTask: addDependenciesToPackageJson(
      tree,
      {
        ...frameworkDependencies[options.framework],
        tslib: tslibVersion,
      },
      {
        ...frameworkDevDependencies[options.framework],
        ...bundlers[options.bundler],
        '@types/node': typesNodeVersion,
      },
      undefined,
      options.keepExistingVersions ?? true
    ),
    frameworkDependencies: frameworkDependencies[options.framework],
  };
}

import {
  installCheckLogger,
  skippedOptionalDependencyLogger,
} from '@pnpm/core-loggers'
import { getSystemNodeVersion } from '@pnpm/engine.runtime.system-version'
import type { SupportedArchitectures } from '@pnpm/types'

import { checkEngine, UnsupportedEngineError, type WantedEngine } from './checkEngine.js'
import { checkPlatform, UnsupportedPlatformError } from './checkPlatform.js'

export type { Engine } from './checkEngine.js'
export type { Platform, WantedPlatform } from './checkPlatform.js'

export {
  UnsupportedEngineError,
  UnsupportedPlatformError,
  type WantedEngine,
}

export function packageIsInstallable (
  pkgId: string,
  pkg: {
    name: string
    version: string
    engines?: WantedEngine
    cpu?: string[]
    os?: string[]
    libc?: string[]
  },
  options: {
    engineStrict?: boolean
    nodeVersion?: string
    optional: boolean
    pnpmVersion?: string
    lockfileDir: string
    supportedArchitectures?: SupportedArchitectures
  }
): boolean | null {
  const warn = checkPackage(pkgId, pkg, options)

  if (warn == null) return true

  installCheckLogger.warn({
    message: warn.message,
    prefix: options.lockfileDir,
  })

  if (options.optional) {
    skippedOptionalDependencyLogger.debug({
      details: warn.toString(),
      package: {
        id: pkgId,
        name: pkg.name,
        version: pkg.version,
      },
      prefix: options.lockfileDir,
      reason: warn.code === 'ERR_PNPM_UNSUPPORTED_ENGINE' ? 'unsupported_engine' : 'unsupported_platform',
    })

    return false
  }

  if (options.engineStrict) throw warn

  return null
}

export function checkPackage (
  pkgId: string,
  manifest: {
    engines?: WantedEngine
    cpu?: string[]
    os?: string[]
    libc?: string[]
  },
  options: {
    nodeVersion?: string
    pnpmVersion?: string
    supportedArchitectures?: SupportedArchitectures
  }
): null | UnsupportedEngineError | UnsupportedPlatformError {
  return checkPlatform(pkgId, {
    cpu: manifest.cpu ?? ['any'],
    os: manifest.os ?? ['any'],
    libc: manifest.libc ?? ['any'],
  }, options.supportedArchitectures) ?? (
    (manifest.engines == null)
      ? null
      : checkEngine(pkgId, manifest.engines, {
        node: options.nodeVersion ?? getSystemNodeVersion() ?? process.version,
        pnpm: options.pnpmVersion,
      })
  )
}

import {Configuration, formatUtils} from '@yarnpkg/core';
import * as ts                      from 'typescript';

export enum CallType {
  REQUIRE,
  RESOLVE,
  IMPORT,
}

export function prettyNodeLocation(configuration: Configuration, node: ts.Node) {
  const {fileName} = node.getSourceFile();
  const {line, character} = ts.getLineAndCharacterOfPosition(
    node.getSourceFile(),
    node.getStart(),
  );

  return [
    `${formatUtils.pretty(configuration, fileName, formatUtils.Type.PATH)}`,
    `${formatUtils.pretty(configuration, line + 1, formatUtils.Type.NUMBER)}`,
    `${formatUtils.pretty(configuration, character + 1, formatUtils.Type.NUMBER)}`,
  ].join(`:`);
}

export function getCallType(call: ts.CallExpression) {
  switch (call.expression.kind) {
    // require(...)
    case ts.SyntaxKind.Identifier: {
      const ident = call.expression as ts.Identifier;
      if (ident.text !== `require`)
        return null;

      return CallType.REQUIRE;
    } break;

    // require.resolve(...)
    case ts.SyntaxKind.PropertyAccessExpression: {
      const access = call.expression as ts.PropertyAccessExpression;
      if (!ts.isIdentifier(access.expression))
        return null;

      const ident = access.expression as ts.Identifier;
      if (ident.text !== `require`)
        return null;

      if (access.name.text !== `resolve`)
        return null;

      return CallType.RESOLVE;
    } break;

    // import(...)
    case ts.SyntaxKind.ImportKeyword: {
      return CallType.IMPORT;
    } break;

    default: {
      return null;
    } break;
  }
}

export function extractStaticString(node: ts.Expression) {
  switch (node.kind) {
    case ts.SyntaxKind.NoSubstitutionTemplateLiteral: {
      const literal = node as ts.NoSubstitutionTemplateLiteral;
      return literal.text;
    } break;

    case ts.SyntaxKind.StringLiteral: {
      const literal = node as ts.StringLiteral;
      return literal.text;
    } break;

    default: {
      return null;
    } break;
  }
}

export function extractStaticName(node: ts.PropertyName) {
  switch (node.kind) {
    case ts.SyntaxKind.Identifier: {
      const identifier = node as ts.Identifier;
      return identifier.text;
    } break;

    case ts.SyntaxKind.StringLiteral: {
      const literal = node as ts.StringLiteral;
      return literal.text;
    } break;

    default: {
      return null;
    } break;
  }
}

